// Python solution
import sys

def binary_search(arr, n, target) -> int:
    if n <= 0:
        return -1
    start = 0
    end = n - 1
    while start <= end:
        mid = start + (end - start) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            start = mid + 1
        else:
            end = mid - 1
    return -1

n = int(input())
arr = list(map(int, input().split()))
target = int(input())
print(binary_search(arr, n, target))

