// C++ solution
#include <iostream>

int binarySearch(int arr[], int n, int target) {
    if (n <= 0) {
        return -1;
    }
    int start = 0;
    int end = n - 1;
    while (start <= end) {
        int mid = start + (end - start) / 2;
        if (arr[mid] == target) {
            return mid;
        } else if (arr[mid] < target) {
            start = mid + 1;
        } else {
            end = mid - 1;
        }
    }
    return -1;

    int main() {
        int n;
        std::cin >> n;
        int arr[n];
        for (int i = 0; i < n; i++) {
            std::cin >> arr[i];
        }
        int target;
        std::cin >> target;
        std::cout << binarySearch(arr, n, target) << std::endl;
        return 0;
    }
